/**
 * Tests for the unified Bash advisory dispatcher's 800-token output budget (#924).
 *
 * The dispatcher (mergeAdvisoryContext) caps consolidated additionalContext at
 * MAX_OUTPUT_TOKENS (800): once a hook's context would push the running total
 * over budget, that hook is skipped. The runtime guard exists
 * (unified-advisory-dispatcher.ts) but no test asserted it — this closes that gap.
 *
 * Strategy: mock the two advisory hooks so the first returns a small context
 * (fits) and the second returns a context far larger than the cap (must be
 * dropped). Then assert the consolidated output stays within budget and contains
 * only the in-budget hook.
 */

import { describe, test, expect, vi } from 'vitest';

const { SMALL_CTX, HUGE_CTX } = vi.hoisted(() => ({
  SMALL_CTX: 'BUDGET_MARKER_ONE small advisory context that fits',
  // ~5.4k chars (well over the 800-token cap) so it must be skipped once SMALL is in
  HUGE_CTX: `BUDGET_MARKER_TWO ${'overflow '.repeat(600)}`,
}));

const ctxResult = (additionalContext: string) => ({
  continue: true,
  suppressOutput: true,
  hookSpecificOutput: { hookEventName: 'PreToolUse', additionalContext },
});

// Phase 1/2 hooks: benign no-ops so only the advisory budget logic is exercised
vi.mock('../../pretool/bash/default-timeout-setter.js', () => ({
  defaultTimeoutSetter: () => ({ continue: true, suppressOutput: true }),
}));
vi.mock('../../pretool/bash/agent-browser-safety.js', () => ({
  agentBrowserSafety: () => ({ continue: true, suppressOutput: true }),
}));
// Advisory hooks (in registry order): first small (fits), second huge (dropped by cap)
vi.mock('../../pretool/bash/error-pattern-warner.js', () => ({
  errorPatternWarner: () => ctxResult(SMALL_CTX),
}));
vi.mock('../../pretool/bash/affected-tests-finder.js', () => ({
  affectedTestsFinder: () => ctxResult(HUGE_CTX),
}));

import { unifiedBashAdvisoryDispatcher } from '../../pretool/bash/unified-advisory-dispatcher.js';
import { estimateTokenCount } from '../../lib/common.js';

const MAX_OUTPUT_TOKENS = 800;

const bashInput = () => ({
  tool_name: 'Bash',
  tool_input: { command: 'echo hello' },
  session_id: 'test-session',
});

describe('unified-advisory-dispatcher output budget (#924)', () => {
  test('caps consolidated additionalContext at the 800-token budget', () => {
    const result = unifiedBashAdvisoryDispatcher(bashInput() as never);
    const context = result.hookSpecificOutput?.additionalContext ?? '';

    // Sanity: the over-budget fixture really would blow the cap on its own
    expect(estimateTokenCount(HUGE_CTX)).toBeGreaterThan(MAX_OUTPUT_TOKENS);
    // The over-budget hook is dropped, so total output stays within budget
    expect(estimateTokenCount(context)).toBeLessThanOrEqual(MAX_OUTPUT_TOKENS);
  });

  test('includes the in-budget hook and drops the over-budget one', () => {
    const result = unifiedBashAdvisoryDispatcher(bashInput() as never);
    const context = result.hookSpecificOutput?.additionalContext ?? '';

    expect(context).toContain('BUDGET_MARKER_ONE'); // small hook fits -> included
    expect(context).not.toContain('BUDGET_MARKER_TWO'); // huge hook exceeds cap -> skipped
  });

  test('stays advisory-only: no permission decision declared (CC 2.1.77)', () => {
    const result = unifiedBashAdvisoryDispatcher(bashInput() as never);
    if (result.hookSpecificOutput) {
      expect(result.hookSpecificOutput).not.toHaveProperty('permissionDecision');
    }
  });
});
